	global.Node = global.window.Node;
	global.navigator = global.window.navigator;
	global.XMLHttpRequest = global.window.XMLHttpRequest;

	let didErr = false;
	const write = process.stderr.write;
	process.stderr.write = function (data) {
		didErr = didErr || !!data;
